INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", 4, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 4, 1, 24015, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", 1, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 4, 2, 24016, "2030/12/17 14:59:59", 4.0);
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "マジムンだらけで目が回るさ～！\nふらふらさ～！", 4, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 4, 3, 24017, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", 2, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 1, 4, 24018, "2030/12/17 14:59:59", 5.2);
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", 6, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 5, 5, 24019, "2030/12/17 14:59:59", 4.2);
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", 2, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 2, 6, 24020, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", 6, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 1, 7, 24021, "2030/12/17 14:59:59", 6.4);
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", 2, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 2, 8, 24022, "2030/12/17 14:59:59", 0.0);
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", 3, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 6, 9, 24023, "2030/12/17 14:59:59", 10.08);
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", 2, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 1, 10, 24024, "2030/12/17 14:59:59", 5.0);
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (0.0, "私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", 2, 24, 110501, 0.0, "カオリ（サマー）", "2019/07/31 12:00:00", 10021, 2, 11, 24025, "2030/12/17 14:59:59", 0.0);
